#include <pthread.h>
#include <stdlib.h>
#include <string.h>

#include "sat.h"

typedef struct {
  int *x;
  int i;
  int n;
  BoolFun f;
  int p;
} ThreadArg;

static int rec_par(int x[], int i, int n, BoolFun f, int p);

static void *thread_run(void *ptr) {
  ThreadArg *arg= ptr;
  int *res= malloc(sizeof(int));

  if (res==NULL)
    exit(1);
  *res= rec_par(arg->x, arg->i, arg->n, arg->f, arg->p);
  free(arg->x);
  free(arg);
  return res;
}

static int rec_par(int x[], int i, int n, BoolFun f, int p) {
  if (i==n)
    return (*f)(x) ? 1 : 0;

  if (i>=p) {
    int cnt;

    x[i]= 0;
    cnt= rec_par(x, i+1, n, f, p);
    x[i]= 1;
    cnt+= rec_par(x, i+1, n, f, p);
    return cnt;
  }
  else {
    pthread_t th;
    ThreadArg *arg= malloc(sizeof(ThreadArg));
    int cnt;
    void *ret;

    if (arg==NULL)
      exit(1);
    arg->x= malloc((size_t)n * sizeof(int));
    if (arg->x==NULL)
      exit(1);
    memcpy(arg->x, x, (size_t)n * sizeof(int));
    arg->i= i+1;
    arg->n= n;
    arg->f= f;
    arg->p= p;

    arg->x[i]= 0;
    if (pthread_create(&th, NULL, thread_run, arg)!=0)
      exit(1);

    x[i]= 1;
    cnt= rec_par(x, i+1, n, f, p);

    if (pthread_join(th, &ret)!=0)
      exit(1);
    cnt+= *(int *)ret;
    free(ret);
    return cnt;
  }
}

int recuento(int n, BoolFun f, int p) {
  int *x= malloc((size_t)n * sizeof(int));
  int cnt;

  if (n>0 && x==NULL)
    exit(1);
  cnt= rec_par(x, 0, n, f, p);
  free(x);
  return cnt;
}

